		const sorted = Array.from(byDate.values()).sort((a, b) =>
			a._sort.localeCompare(b._sort),
		);

		return {
			chartData: sorted,
			models: Array.from(modelSet),
		};
	}, [data]);

	if (chartData.length === 0) return null;

	return (
		<ResponsiveContainer width="100%" height={400}>
			<AreaChart
				data={chartData}
				margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
			>
				<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
				<XAxis
					dataKey="date"
					tick={{ fontSize: 12 }}
					angle={-45}
					textAnchor="end"
					height={80}
				/>
				<YAxis tick={{ fontSize: 12 }} tickFormatter={formatCompactNumber} />
				<Tooltip
					contentStyle={{
						backgroundColor: tooltipBg,
						border: `1px solid ${tooltipBorder}`,
						borderRadius: "2px",
						padding: "12px",
					}}
					formatter={(value, name) => [
						formatCompactNumber((value as number) ?? 0),
						shortenModelName(String(name ?? "")),
					]}
					labelFormatter={(label) => label}
				/>
				<Legend formatter={shortenModelName} />
				{models.map((model, i) => (
					<Area
						key={model}
						type="monotone"
						dataKey={model}
						stackId="1"
						fill={MODEL_COLORS[i % MODEL_COLORS.length]}
						stroke={MODEL_COLORS[i % MODEL_COLORS.length]}
						fillOpacity={0.6}
						name={model}
					/>
				))}
			</AreaChart>
		</ResponsiveContainer>
	);
}

